    discord: {
      enabled: true,
      token: &quot;your-bot-token&quot;,
      mediaMaxMb: 8,
      allowBots: false,
      actions: {
        reactions: true,
        stickers: true,
        polls: true,
        permissions: true,
        messages: true,
        threads: true,
        pins: true,
        search: true,
        memberInfo: true,
        roleInfo: true,
        roles: false,
        channelInfo: true,
        voiceStatus: true,
        events: true,
        moderation: false,
      },
      replyToMode: &quot;off&quot;, // off | first | all
      dmPolicy: &quot;pairing&quot;,
      allowFrom: [&quot;1234567890&quot;, &quot;123456789012345678&quot;],
      dm: { enabled: true, groupEnabled: false, groupChannels: [&quot;openclaw-dm&quot;] },
      guilds: {
        &quot;123456789012345678&quot;: {
          slug: &quot;friends-of-openclaw&quot;,
          requireMention: false,
          ignoreOtherMentions: true,
          reactionNotifications: &quot;own&quot;,
          users: [&quot;987654321098765432&quot;],
          channels: {
            general: { allow: true },
            help: {
              allow: true,
              requireMention: true,
              users: [&quot;987654321098765432&quot;],
              skills: [&quot;docs&quot;],
              systemPrompt: &quot;Short answers only.&quot;,
            },
          },
        },
      },
      historyLimit: 20,
      textChunkLimit: 2000,
      chunkMode: &quot;length&quot;, // length | newline
      streaming: &quot;off&quot;, // off | partial | block | progress (progress maps to partial on Discord)
      maxLinesPerMessage: 17,
      ui: {
        components: {
          accentColor: &quot;#5865F2&quot;,
        },
      },
      threadBindings: {
        enabled: true,
        idleHours: 24,
        maxAgeHours: 0,
        spawnSubagentSessions: false, // opt-in for sessions_spawn({ thread: true })
      },
      voice: {
        enabled: true,
        autoJoin: [
          {
            guildId: &quot;123456789012345678&quot;,
            channelId: &quot;234567890123456789&quot;,
          },
        ],
        daveEncryption: true,
        decryptionFailureTolerance: 24,
        tts: {
          provider: &quot;openai&quot;,
          openai: { voice: &quot;alloy&quot; },
        },
      },
      retry: {
        attempts: 3,
        minDelayMs: 500,
        maxDelayMs: 30000,
        jitter: 0.1,
      },
    },
