          image: &quot;openclaw-sandbox:bookworm-slim&quot;,
          containerPrefix: &quot;openclaw-sbx-&quot;,
          workdir: &quot;/workspace&quot;,
          readOnlyRoot: true,
          tmpfs: [&quot;/tmp&quot;, &quot;/var/tmp&quot;, &quot;/run&quot;],
          network: &quot;none&quot;,
          user: &quot;1000:1000&quot;,
          capDrop: [&quot;ALL&quot;],
